PART = '            st.write(res.get("message"))\n\n    m = res.get("market", {}) or {}\n    if not m:\n        st.info("No market analytics yet for this block.")\n        return\n\n    c = st.columns(6)\n    c[0].metric("Price", round(_safe_num(m.get("price_now")), 5))\n    c[1].metric("10s %", round(_safe_num(m.get("sec10_pct")), 4))\n    c[2].metric("1m %", round(_safe_num(m.get("min1_pct")), 4))\n    c[3].metric("10m %", round(_safe_num(m.get("min10_pct")), 4))\n    c[4].metric("DVE %", round(_safe_num(m.get("directional_efficiency")), 2))\n    c[5].metric("Trust", f"{round(_safe_num(m.get(\'trust\')),1)}%")\n\n    d = st.columns(5)\n    for col, title, key, status_name in [\n        (d[0], "Fat Tail Z", "fat_tail_z", "fat_tail_z"),\n        (d[1], "Kurtosis", "kurtosis", "fat_tail_z"),\n        (d[2], "Rising Eff %", "efficiency_rising", "efficiency_rising"),\n        (d[3], "Falling Eff %", "efficiency_falling", "efficiency_falling"),\n        (d[4], "Accel", "accel_abs", "price_accel_abs"),\n    ]:\n        val = _safe_num(m.get(key))\n        if key == "fat_tail_z" and not m.get("fat_tail_available", False):\n            col.metric(title, "N/A")\n            col.caption(f"⚪ DATA CHECK: {m.get(\'fat_tail_note\', \'Fat-tail is not reliable yet.\')}")\n            continue\n        s, note = _analytics_status(status_name, abs(val) if "accel" in key else val)\n        col.metric(title, round(val, 3))\n        col.caption(f"{_status_badge(s)} {s}: {note}")\n\n    regime = m.get("regime", "UNKNOWN")\n    direction = m.get("trend_direction", "UNKNOWN")\n    score = round(_regime_score(m), 1)\n    if any(x in str(regime) for x in ["LIMIT", "EXHAUSTION", "STOPPING", "SHOCK"]):\n        st.warning(f"Important: {regime} | Direction: {direction} | Score: {score}")\n    elif any(x in str(regime) for x in ["STARTING", "CONTINUING", "CONTINUES"]):\n        st.success(f"Important: {regime} | Direction: {direction} | Score: {score}")\n    else:\n        st.info(f"Regime: {regime} | Direction: {direction} | Score: {score}")\n\n\n\ndef _append_alert_row(row):\n    try:\n        from core.database import append_csv\n        append_csv("doo_exit_alerts", row)\n    except Exception:\n        pass\n\n\ndef _get_account_margin_level():\n    info = st.session_state.get("account_snapshot", {})\n    if isinstance(info, dict):\n        return _safe_num(info.get("margin_level"), 0.0)\n    return 0.0\n\n\ndef _positions_df_from_account():\n    """Return current MT5/Doo positions normalized for analytics only; never sends orders."""\n    info = st.session_state.get("account_snapshot", {}) or {}\n    positions = info.get("positions", []) if isinstance(info, dict) else []\n    if not positions:\n        return pd.DataFrame()\n    try:\n        df = pd.DataFrame([dict(p) if not isinstance(p, dict) else p for p in positions])\n    except Exception:\n        return pd.DataFrame()\n    if df.empty:\n        return pd.DataFrame()\n    if "type" in df.columns and "side" not in df.columns:\n        df["side"] = df["type"].map({0: "BUY", 1: "SELL"}).fillna(df["type"].astype(str))\n    elif "side" not in df.columns:\n        df["side"] = "UNKNOWN"\n    for col in ["profit", "volume", "price_open", "price_current", "swap", "commission"]:\n        if col in df.columns:\n            df[col] = pd.to_numeric(df[col], errors="coerce").fillna(0.0)\n    return df\n\n\ndef _basket_profit_health(close_signal):\n    """Extra confirmation layer requested by user.\n\n    EXIT SELL is only fully confirmed if the SELL basket is not mostly negative.\n    EXIT BUY is only fully confirmed if the BUY basket is not mostly negative.\n    Under 40% winners does not force the signal to disappear; it downgrades it to\n    WATCH / recovery only, because realizing that basket may reduce balance.\n    """\n    df = _positions_df_from_account()\n    side = "SELL" if str(close_signal).upper() == "EXIT SELL" else "BUY" if str(close_signal).upper() == "EXIT BUY" else ""\n    empty = {\n        "side": side or "N/A", "count": 0, "profit_count": 0, "profit_pct": 0.0,\n        "side_pl": 0.0, "ok_40": False, "note": "No account positions loaded; basket P/L gate cannot confirm."\n    }\n    if df.empty or not side:\n        return empty\n    sdf = df[df["side"].astype(str).str.upper() == side].copy()\n    if sdf.empty:\n        empty["note"] = f"No {side} positions found."\n        return empty\n    profit = pd.to_numeric(sdf.get("profit", 0.0), errors="coerce").fillna(0.0)\n    count = int(len(sdf))\n    profit_count = int((profit > 0).sum())\n    profit_pct = profit_count / max(count, 1) * 100.0\n    side_pl = float(profit.sum())\n    ok = profit_pct >= 40.0 or side_pl >= 0.0\n    if ok:\n        note = f"{side} basket P/L gate OK: {profit_count}/{count} positions profitable ({profit_pct:.1f}%), total {side} P/L={side_pl:.2f}."\n    else:\n        note = f"{side} basket P/L gate LOW: only {profit_count}/{count} profitable ({profit_pct:.1f}%), total {side} P/L={side_pl:.2f}. Treat as WATCH/recovery, not full confirmation."\n    return {"side": side, "count": count, "profit_count": profit_count, "profit_pct": profit_pct, "side_pl": side_pl, "ok_40": ok, "note": note}\n\n\ndef _h1_does_not_worsen(h1_market):\n    if not h1_market:\n        return False, "H1 block unavailable"\n    h1_dve = _safe_num(h1_market.get("directional_efficiency"))\n    h1_falling = _safe_num(h1_market.get("efficiency_falling"))\n    h1_trust = _safe_num(h1_market.get("trust"))\n    h1_regime = str(h1_market.get("regime", "")).upper()\n    bad_regime = any(x in h1_regime for x in ["EXHAUSTION", "STOPPING", "SHOCK"])\n    ok = h1_dve >= 30 and h1_falling <= 25 and h1_trust >= 8 and not bad_regime\n    note = f"H1 DVE={h1_dve:.2f}, Falling={h1_falling:.2f}, Trust={h1_trust:.2f}, Regime={h1_regime or \'N/A\'}"\n    return ok, note\n\n\ndef _evaluate_one_hour_exit_sound(results):\n    """Track the user\'s requested 1-hour alert rule.\n\n    Rule: M1 DVE > 60, Rising Eff > 35, Falling Eff near 0, H1 does not worsen,\n    and margin level improves above 70-80%. The alert fires only after the same\n    side stays qualified for 1 hour, then records the last EXIT BUY/SELL signal.\n    """\n    results = results or {}\n    m1 = (results.get("m1_600") or {}).get("market", {}) or {}\n    h1 = (results.get("h1_600") or {}).get("market", {}) or {}\n    if not m1:\n        return\n\n    margin_level = _get_account_margin_level()\n    direction = str(m1.get("trend_direction", "")).upper()\n    dve = _safe_num(m1.get("directional_efficiency"))\n    rising = _safe_num(m1.get("efficiency_rising"))\n    falling = _safe_num(m1.get("efficiency_falling"))\n    h1_ok, h1_note = _h1_does_not_worsen(h1)\n    margin_ok = margin_level >= 70.0\n\n    signal = "EXIT SELL" if direction in ["UP", "BUY"] else "EXIT BUY" if direction in ["DOWN", "SELL"] else "WAIT"\n    basket = _basket_profit_health(signal)\n    basket_ok = bool(basket.get("ok_40", False))\n    # Core trend rule + account/basket P/L gate.  This prevents a full confirmation\n    # when the selected side is still mostly negative.  It can still show WATCH.\n    core_ok = bool(dve > 60 and rising > 35 and falling <= 3.0 and h1_ok and margin_ok and basket_ok and direction in ["UP", "DOWN", "BUY", "SELL"])\n    tracker = st.session_state.setdefault("one_hour_exit_alert_tracker", {})\n    now = time.time()\n    track_key = f"{signal}_{st.session_state.get(\'symbol\',\'XAUUSD\')}"\n\n    st.markdown("#### 🔔 One-hour exit opportunity sound rule")\n    cols = st.columns(7)\n    cols[0].metric("M1 DVE > 60", "YES" if dve > 60 else "NO")\n    cols[0].caption(f"Now {dve:.2f}%")\n    cols[1].metric("Rising > 35", "YES" if rising > 35 else "NO")\n    cols[1].caption(f"Now {rising:.2f}%")\n    cols[2].metric("Falling near 0", "YES" if falling <= 3 else "NO")\n    cols[2].caption(f"Now {falling:.2f}%")\n    cols[3].metric("H1 not worse", "YES" if h1_ok else "NO")\n    cols[3].caption(h1_note[:90])\n    cols[4].metric("Margin ≥70%", "YES" if margin_ok else "NO")\n    cols[4].caption(f"Now {margin_level:.2f}%")\n    cols[5].metric("Candidate", signal)\n    cols[6].metric(f"{basket.get(\'side\',\'Side\')} profit ≥40%", "YES" if basket_ok else "NO")\n    cols[6].caption(basket.get("note", "")[:120])\n    note_key = "last_exit_sell_signal_time" if signal == "EXIT SELL" else "last_exit_buy_signal_time"\n    recent = recent_signal_caption(note_key, max_hours=21)\n    cols[5].caption(recent or "No recent signal within 21h")\n\n    if core_ok:\n        if tracker.get("key") != track_key:\n            tracker.clear()\n            tracker.update({"key": track_key, "first_seen": now, "signal": signal})\n        held = max(0, now - float(tracker.get("first_seen", now)))\n        remaining = max(0, 3600 - int(held))\n        if held >= 3600:\n            if signal == "EXIT SELL":\n                set_recent_signal("last_exit_sell_signal_time")\n            elif signal == "EXIT BUY":\n                set_recent_signal("last_exit_buy_signal_time")\n            _append_alert_row({\n                "time": pd.Timestamp.now(),\n                "symbol": st.session_state.get("symbol", "XAUUSD"),\n                "signal": signal,\n                "source": "one_hour_threshold_rule",\n                "m1_dve": dve,\n                "m1_rising_eff": rising,\n                "m1_falling_eff": falling,\n                "h1_note": h1_note,\n                "margin_level": margin_level,\n                "direction": direction,\n                "basket_side": basket.get("side"),\n                "basket_profit_pct": basket.get("profit_pct"),\n                "basket_side_pl": basket.get("side_pl"),\n            })\n            sound_alert(\n                f"one_hour_{signal.lower().replace(\' \', \'_\')}",\n                f"🔔 {signal} one-hour threshold reached",\n                "Your configured one-hour rule stayed aligned: M1 DVE >60, Rising >35, Falling near 0, H1 not worse, and margin ≥70%.",\n                severity="danger",\n                cooldown_seconds=600,\n            )\n        else:\n            st.info(f"{signal} candidate is building. Hold-time before sound: about {remaining // 60}m {remaining % 60}s more if conditions stay true.")\n    else:\n        tracker.clear()\n        if signal in ["EXIT SELL", "EXIT BUY"] and not basket_ok:\n            st.warning(f"{signal} WATCH only: trend candidate exists, but basket-profit gate is not safe enough. {basket.get(\'note\',\'\')}")\n        st.caption("One-hour sound rule is not armed yet. It resets when any required condition fails.")\n\n\n\ndef _doo_session_name_from_hour(hour):\n    """Return practical trading session label from latest candle hour.\n\n    Uses the latest candle timestamp first because the user wants the panel to\n    judge the *current loaded data*, not only the computer clock. Hours are read\n    directly from the dataframe timestamp, so it stays compatible with MT5 broker\n    server time, TwelveData time, and fallback data.\n    """\n    h = int(hour) % 24\n    if 0 <= h < 7:\n        return "ASIA", "Range-building / liquidity thinner", 7\n    if 7 <= h < 13:\n        return "LONDON", "Main impulse / breakout risk", 13\n    if 13 <= h < 16:\n        return "LONDON-NY OVERLAP", "Highest movement + stop-out danger", 16\n    if 16 <= h < 21:\n        return "NEW YORK", "Continuation or reversal decision zone", 21\n    return "ROLLOVER / LATE NY", "Spread + fake-move caution", 24\n\n\ndef _latest_m1_for_session(results):\n    """Best available M1 dataframe for the live session intelligence block."""\n    # Prefer the already-built deep M1 frame because it reflects this inner tab.\n    for key in ("m1_600", "m1_60000"):\n        res = (results or {}).get(key, {}) or {}\n        frame = res.get("frame")\n        if isinstance(frame, pd.DataFrame) and not frame.empty:\n            norm = _normalize_local(frame)\n            if not norm.empty:\n                return norm, res.get("source", "DEEP_M1_FRAME")\n    # Fallback to the shared/Home/Doo dataframe.\n    df = _shared_market_df("M1", 600)\n    if not df.empty:\n        return df, "SHARED_HOME_M1"\n    return pd.DataFrame(), "NO_M1_DATA"\n\n\ndef _pct(a, b):\n    a = _safe_num(a)\n    b = _safe_num(b)\n    if abs(b) < 1e-12:\n        return 0.0\n    return (a - b) / abs(b) * 100.0\n\n\ndef _account_current_values():\n    """Read account values from the current app state; market-only data remains allowed."""\n    info = st.session_state.get("account_snapshot", {}) or {}\n    equity = _safe_num(info.get("equity", info.get("current_equity", 0)))\n    margin = _safe_num(info.get("margin", info.get("current_margin", 0)))\n    margin_level = _safe_num(info.get("margin_level", info.get("margin_level_pct", 0)))\n    if margin_level <= 0 and margin > 0:\n        margin_level = equity / max(margin, 1e-9) * 100.0\n    stopout = _safe_num(info.get("stopout_level", info.get("stopout_level_pct", 30.0)), 30.0)\n    profit = _safe_num(info.get("profit", info.get("floating_pl", info.get("floating_profit", 0))))\n    positions = _safe_int(info.get("positions", info.get("positions_total", 0)))\n    return {\n        "equity": equity,\n        "margin": margin,\n        "margin_level": margin_level,\n        "stopout": stopout,\n        "gap": margin_level - stopout,\n        "floating_pl": profit,\n        "positions": positions,\n        "has_account": bool(info),\n    }\n\n\ndef _calc_current_doo_session_intelligence(results):\n    """Big live decision helper for Doo Prime Analysis.\n\n    It combines: latest M1 candle/session, short-term M1 movement, deep-frame\n    DVE/trust/fat-tail, and current margin survival. The output is designed for\n    st.metric so the user can immediately see what problem is dangerous *now*.\n    """\n    df, source = _latest_m1_for_session(results)\n    acct = _account_current_values()\n    if df.empty:\n        return {"ok": False, "message": "No M1/current dataframe available yet.", "source": source, "account": acct}\n\n    df = _normalize_local(df).tail(600).copy()\n    last = df.iloc[-1]\n    last_time = pd.to_datetime(last["time"], errors="coerce")\n    hour = int(last_time.hour) if pd.notna(last_time) else int(pd.Timestamp.now().hour)\n    session, session_note, next_hour = _doo_session_name_from_hour(hour)\n    mins_next = ((next_hour - hour) % 24) * 60 - (int(last_time.minute) if pd.notna(last_time) else 0)\n    if mins_next <= 0:\n        mins_next += 24 * 60\n\n    close = float(last["close"])\n    move_1 = _pct(close, df["close"].iloc[-2]) if len(df) >= 2 else 0.0\n    move_10 = _pct(close, df["close"].iloc[-11]) if len(df) >= 11 else 0.0\n    move_60 = _pct(close, df["close"].iloc[-61]) if len(df) >= 61 else 0.0\n    range_120 = 0.0\n    if len(df) >= 120:\n        tail = df.tail(120)\n        range_120 = (float(tail["high"].max()) - float(tail["low"].min())) / max(abs(close), 1e-9) * 100.0\n\n    # Deep metrics from current inner-tab results.\n    deep_rows = []\n    for key, res in (results or {}).items():\n        m = (res or {}).get("market", {}) or {}\n        if not m:\n            continue\n        deep_rows.append({\n            "direction": str(m.get("trend_direction", "WAIT")).upper(),\n            "dve": _safe_num(m.get("directional_efficiency")),\n            "rising": _safe_num(m.get("efficiency_rising")),\n            "falling": _safe_num(m.get("efficiency_falling")),\n            "trust": _safe_num(m.get("trust")),\n            "tail": abs(_safe_num(m.get("fat_tail_z"))) if m.get("fat_tail_available", False) else 0.0,\n            "score": _regime_score(m),\n        })\n    metrics = pd.DataFrame(deep_rows)\n    if not metrics.empty:\n        buy_votes = int(metrics["direction"].isin(["BUY", "UP"]).sum())\n        sell_votes = int(metrics["direction"].isin(["SELL", "DOWN"]).sum())\n        avg_dve = float(metrics["dve"].mean())\n        avg_trust = float(metrics["trust"].mean())\n        avg_score = float(metrics["score"].mean())\n        max_tail = float(metrics["tail"].max())\n    else:\n        buy_votes = sell_votes = 0\n        avg_dve = avg_trust = avg_score = max_tail = 0.0\n\n    if buy_votes > sell_votes:\n        pressure = "BUY PRESSURE"\n    elif sell_votes > buy_votes:\n        pressure = "SELL PRESSURE"\n    else:\n        pressure = "MIXED / WAIT"\n\n    # Session-specific danger multiplier. Overlap and London get stricter.\n    session_mult = {"ASIA": 0.85, "LONDON": 1.15, "LONDON-NY OVERLAP": 1.35, "NEW YORK": 1.10}.get(session, 1.25)\n    margin_risk = 0.0\n    if acct["margin_level"] > 0:\n        if acct["gap"] < 20:\n            margin_risk = 45\n        elif acct["gap"] < 40:\n            margin_risk = 30\n        elif acct["gap"] < 60:\n            margin_risk = 18\n        else:\n            margin_risk = 8\n    market_risk = min(45, abs(move_10) * 8 + avg_dve * 0.20 + max_tail * 8 + max(0, range_120 - 1.5) * 3)\n    problem_score = max(0.0, min(100.0, (margin_risk + market_risk) * session_mult))\n\n    if problem_score >= 75:\n        risk_label = "DANGEROUS"\n    elif problem_score >= 55:\n        risk_label = "HIGH WATCH"\n    elif problem_score >= 35:\n        risk_label = "CAUTION"\n    else:\n        risk_label = "NORMAL"\n\n    # Practical action: survival first, direction second.\n    if acct["margin_level"] and acct["gap"] <= 35:\n        action = "PAIRED REDUCE ONLY"\n        action_note = "Margin gap is thin; avoid full one-side exit unless position-profit gate confirms."\n    elif pressure == "BUY PRESSURE" and avg_dve >= 55 and avg_trust >= 45:\n        action = "WATCH EXIT SELL"\n        action_note = "Up pressure can hurt SELL basket; confirm SELL basket profit ratio before full exit."\n    elif pressure == "SELL PRESSURE" and avg_dve >= 55 and avg_trust >= 45:\n        action = "WATCH EXIT BUY"\n        action_note = "Down pressure can hurt BUY basket; confirm BUY basket profit ratio before full exit."\n    else:\n        action = "HOLD / WAIT"\n        action_note = "No clean one-way confirmation from current deep data."\n\n    return {\n        "ok": True,\n        "source": source,\n        "session": session,\n        "session_note": session_note,\n        "last_time": last_time.strftime("%Y-%m-%d %H:%M:%S") if pd.notna(last_time) else "N/A",\n        "mins_next": int(max(mins_next, 0)),\n        "close": close,\n        "move_1": move_1,\n        "move_10": move_10,\n        "move_60": move_60,\n        "range_120": range_120,\n        "buy_votes": buy_votes,\n        "sell_votes": sell_votes,\n        "avg_dve": avg_dve,\n        "avg_trust": avg_trust,\n        "avg_score": avg_score,\n        "max_tail": max_tail,\n        "pressure": pressure,\n        "problem_score": problem_score,\n        "risk_label": risk_label,\n        "action": action,\n        "action_note": action_note,\n        "account": acct,\n    }\n\n\ndef _render_current_doo_session_metric_panel(results):\n    """Large st.metric panel placed at the top of Doo Prime Analysis."""\n    x = _calc_current_doo_session_intelligence(results)\n    st.markdown("### 🧭 Current Data Session Intelligence")\n    st.caption("This block reads the latest loaded M1/current data + account margin first, then explains the live problem with metrics.")\n    if not x.get("ok"):\n        st.warning(x.get("message", "No current data yet."))\n        return\n\n    acct = x.get("account", {}) or {}\n    r1 = st.columns(6)\n    r1[0].metric("Session Now", x["session"])\n    r1[0].caption(x["session_note"])\n'
